<script setup lang="ts">
import { ref } from 'vue';
import { summarizeMessages } from '../总结功能';

defineEmits<{
  (e: 'navigate', tab: string): void;
}>();

const isSummarizing = ref(false);

// 快速总结最近10条消息
async function quickSummarize() {
  if (isSummarizing.value) return;

  isSummarizing.value = true;

  try {
    // 获取最后一条消息ID
    let lastMessageId = 0;
    const TH = (window as any).TavernHelper;

    if (TH?.getLastMessageId) {
      lastMessageId = TH.getLastMessageId();
    } else if (typeof SillyTavern !== 'undefined' && Array.isArray(SillyTavern.chat)) {
      lastMessageId = SillyTavern.chat.length - 1;
    }

    if (lastMessageId < 5) {
      (window as any).toastr?.warning('对话太短，至少需要5条消息');
      return;
    }

    // 总结最近10条
    const startId = Math.max(0, lastMessageId - 9);
    const endId = lastMessageId;

    (window as any).toastr?.info(`开始总结楼层 ${startId}-${endId}...`);

    const summary = await summarizeMessages(startId, endId);

    (window as any).toastr?.success('总结完成！查看"记忆管理"标签页');
    console.log('快速总结结果:', summary);
  } catch (error: any) {
    console.error('快速总结失败:', error);
    (window as any).toastr?.error('总结失败: ' + error.message);
  } finally {
    isSummarizing.value = false;
  }
}
</script>

